                    if (claimed) continue;
                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) { best_dist = dist; best_idx = w; }
                }

                if (best_idx == -1) {
                    int tr = (plan.r_min + plan.r_max) / 2;
                    int tc = (plan.c_min + plan.c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        for (int r = plan.r_min; r <= plan.r_max; r++) {
                            for (int c = plan.c_min; c <= plan.c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_corner_target; }
                            }
                        }
                        found_corner_target:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    Point wall_target = my_walls[best_idx];
                    Point stand_pos = {-1, -1};
