# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// === STRATEGY: Concentrated single-wall strip ===
// Build one full-width wall (30 cells) along one edge of the grid,
// creating a large pet-free strip. ALL humans cooperate on this single wall.
// The strip uses 3 grid boundaries + 1 built wall.
//
// Additionally, compare against L-shaped corner pairs as fallback.

struct StripPlan {
    int edge; // 0=top, 1=bottom, 2=left, 3=right
    int wall_pos; // row or col of the wall
    int depth; // depth of the safe strip (# rows or cols)
    int area;
    int pets_inside;
    double score;
    // Safe zone boundaries
    int r_min, r_max, c_min, c_max;
};

struct CornerPlan {
    int corner; // 0=TL, 1=TR, 2=BL, 3=BR
    int wall_row, wall_col;
    int area, cost, pets_inside;
    double score;
    int r_min, r_max, c_min, c_max;
};

std::vector<Point> get_strip_wall_cells(const StripPlan& plan) {
    std::vector<Point> cells;
    if (plan.edge == 0) { // top: horizontal wall at wall_pos
        for (int c = 1; c <= GRID_SIZE; c++) cells.push_back({plan.wall_pos, c});
    } else if (plan.edge == 1) { // bottom: horizontal wall at wall_pos
        for (int c = 1; c <= GRID_SIZE; c++) cells.push_back({plan.wall_pos, c});
    } else if (plan.edge == 2) { // left: vertical wall at wall_pos
        for (int r = 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_pos});
    } else { // right: vertical wall at wall_pos
        for (int r = 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_pos});
    }
    return cells;
}

std::vector<Point> get_corner_wall_cells(const CornerPlan& plan) {
    std::vector<Point> cells;
    if (plan.corner == 0) {
        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
    } else if (plan.corner == 1) {
        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
    } else if (plan.corner == 2) {
        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
    } else {
        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
    }
    return cells;
}

// Strategy selection
int strategy_mode; // 0=strip, 1=corner_pair
StripPlan best_strip;
CornerPlan plans[2];
int num_plans;

std::vector<Point> wall_cells_to_build;
int human_wall_section[10]; // which section of wall cells this human is assigned to

void find_best_strip(StripPlan& best) {
    best.score = -1;

    for (int edge = 0; edge < 4; edge++) {
        int max_depth = (edge < 2) ? 14 : 14; // don't go past halfway
        for (int depth = 3; depth <= max_depth; depth++) {
            StripPlan sp;
            sp.edge = edge;
            sp.depth = depth;

            if (edge == 0) { // top strip: rows 1..depth, wall at row depth+1
                sp.wall_pos = depth + 1;
                sp.r_min = 1; sp.r_max = depth;
                sp.c_min = 1; sp.c_max = GRID_SIZE;
            } else if (edge == 1) { // bottom strip: rows (30-depth+1)..30, wall at row (30-depth)
                sp.wall_pos = GRID_SIZE - depth;
                sp.r_min = GRID_SIZE - depth + 1; sp.r_max = GRID_SIZE;
                sp.c_min = 1; sp.c_max = GRID_SIZE;
            } else if (edge == 2) { // left strip: cols 1..depth, wall at col depth+1
                sp.wall_pos = depth + 1;
                sp.r_min = 1; sp.r_max = GRID_SIZE;
                sp.c_min = 1; sp.c_max = depth;
            } else { // right strip: cols (30-depth+1)..30, wall at col (30-depth)
                sp.wall_pos = GRID_SIZE - depth;
                sp.r_min = 1; sp.r_max = GRID_SIZE;
                sp.c_min = GRID_SIZE - depth + 1; sp.c_max = GRID_SIZE;
            }

            sp.area = (sp.r_max - sp.r_min + 1) * (sp.c_max - sp.c_min + 1);
            sp.pets_inside = 0;

            for (auto& p : pets) {
                if (p.r >= sp.r_min && p.r <= sp.r_max && p.c >= sp.c_min && p.c <= sp.c_max) {
                    sp.pets_inside++;
                }
            }

            // Also count pets adjacent to the wall (they'll block construction)
            int pets_near_wall = 0;
            if (edge < 2) {
                for (auto& p : pets) {
                    if (std::abs(p.r - sp.wall_pos) <= 1 && p.c >= 1 && p.c <= GRID_SIZE)
                        pets_near_wall++;
                }
            } else {
                for (auto& p : pets) {
                    if (std::abs(p.c - sp.wall_pos) <= 1 && p.r >= 1 && p.r <= GRID_SIZE)
                        pets_near_wall++;
                }
            }

            // Score: area/900 * 2^(-pets_inside), penalized for construction difficulty
            double base_score = (double)sp.area / 900.0 * std::pow(2.0, -(double)sp.pets_inside);

            // Strong preference for 0 pets inside
            double pet_bonus = (sp.pets_inside == 0) ? 2.5 : (sp.pets_inside == 1) ? 1.0 : 0.3;

            // Penalty for pets near wall (they block construction)
            double near_penalty = 1.0 / (1.0 + pets_near_wall * 0.3);

            // Slight penalty for larger walls (30 cells is fixed cost)
            // But reward larger area strongly
            double area_bonus = std::sqrt((double)sp.area / 150.0);

            sp.score = base_score * pet_bonus * near_penalty * area_bonus;

            if (sp.score > best.score) {
                best = sp;
            }
        }
    }
}

void find_best_corner(int corner_id, CornerPlan& best) {
    best.score = -1;
    for (int wr = 2; wr <= 29; wr++) {
        for (int wc = 2; wc <= 29; wc++) {
            int r_min, r_max, c_min, c_max, cost;
            if (corner_id == 0) { r_min=1; r_max=wr-1; c_min=1; c_max=wc-1; cost=wc+(wr-1); }
            else if (corner_id == 1) { r_min=1; r_max=wr-1; c_min=wc+1; c_max=GRID_SIZE; cost=(GRID_SIZE-wc+1)+(wr-1); }
            else if (corner_id == 2) { r_min=wr+1; r_max=GRID_SIZE; c_min=1; c_max=wc-1; cost=wc+(GRID_SIZE-wr); }
            else { r_min=wr+1; r_max=GRID_SIZE; c_min=wc+1; c_max=GRID_SIZE; cost=(GRID_SIZE-wc+1)+(GRID_SIZE-wr); }

            int area = (r_max - r_min + 1) * (c_max - c_min + 1);
            if (area < 50 || cost > 40) continue;

            int pets_inside = 0;
            for (auto& p : pets) {
                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max)
                    pets_inside++;
            }

            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
            double time_factor = 1.0 / (1.0 + cost * 0.01);
            double pet_bonus = (pets_inside == 0) ? 2.0 : 1.0;
            double score = base_score * time_factor * pet_bonus;

            if (score > best.score) {
                best.corner = corner_id;
                best.wall_row = wr; best.wall_col = wc;
                best.area = area; best.cost = cost;
                best.pets_inside = pets_inside; best.score = score;
                best.r_min = r_min; best.r_max = r_max;
                best.c_min = c_min; best.c_max = c_max;
            }
        }
    }
}

void choose_strategy() {
    // Find best strip
    StripPlan strip;
    find_best_strip(strip);

    // Find best corner pair
    CornerPlan corners[4];
    for (int i = 0; i < 4; i++) find_best_corner(i, corners[i]);

    double best_pair_score = -1;
    int best_pair[2] = {0, 3};
    int pairs[2][2] = {{0, 3}, {1, 2}};
    for (auto& pair : pairs) {
        double combined = corners[pair[0]].score + corners[pair[1]].score;
        if (combined > best_pair_score) {
            best_pair_score = combined;
            best_pair[0] = pair[0]; best_pair[1] = pair[1];
        }
    }

    // Compare strip vs corner pair
    // The strip gets ALL humans in one zone, so effective per-person score is higher
    // Corner pair splits humans between two zones
    // For strip: all M humans get area/900 (assuming 0 pets)
    // For corners: humans split between two smaller areas
    double strip_effective = strip.score;
    double corner_effective = best_pair_score * 0.5; // halved because split

    if (strip_effective > corner_effective && strip.pets_inside <= 1) {
        strategy_mode = 0; // strip
        best_strip = strip;
        wall_cells_to_build = get_strip_wall_cells(strip);
    } else {
        strategy_mode = 1; // corner pair
        num_plans = 2;
        plans[0] = corners[best_pair[0]];
        plans[1] = corners[best_pair[1]];
    }
}

// Assign humans to wall sections for strip strategy
void assign_strip_sections() {
    int total_cells = (int)wall_cells_to_build.size();
    int cells_per_human = total_cells / M;
    int extra = total_cells % M;

    // Sort humans by their position along the wall axis for efficient assignment
    std::vector<std::pair<int, int>> human_pos(M); // (position_along_wall, human_idx)
    for (int i = 0; i < M; i++) {
        if (best_strip.edge < 2) { // horizontal wall
            human_pos[i] = {humans[i].c, i};
        } else { // vertical wall
            human_pos[i] = {humans[i].r, i};
        }
    }
    std::sort(human_pos.begin(), human_pos.end());

    int start = 0;
    for (int rank = 0; rank < M; rank++) {
        int idx = human_pos[rank].second;
        int my_count = cells_per_human + (rank < extra ? 1 : 0);
        human_wall_section[idx] = start; // start index into wall_cells_to_build
        start += my_count;
    }
}

// For corner pair strategy
int human_plan_assignment[10];
std::vector<Point> plan_walls[2];

void assign_humans_corners() {
    int count0 = M / 2;
    std::vector<std::pair<double, int>> preference(M);
    for (int i = 0; i < M; i++) {
        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
        preference[i] = {d0 - d1, i};
    }
    std::sort(preference.begin(), preference.end());
    int assigned0 = 0;
    for (auto& [pref, idx] : preference) {
        if (assigned0 < count0) { human_plan_assignment[idx] = 0; assigned0++; }
        else { human_plan_assignment[idx] = 1; }
    }
}

bool is_safe_side_strip(int r, int c) {
    return r >= best_strip.r_min && r <= best_strip.r_max &&
           c >= best_strip.c_min && c <= best_strip.c_max;
}

bool is_safe_side_corner(const CornerPlan& plan, int r, int c) {
    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_strategy();

    if (strategy_mode == 0) {
        assign_strip_sections();
    } else {
        for (int p = 0; p < num_plans; p++)
            plan_walls[p] = get_corner_wall_cells(plans[p]);
        assign_humans_corners();
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        if (strategy_mode == 0) {
            // Strip strategy: all humans build one wall cooperatively
            int total_cells = (int)wall_cells_to_build.size();
            int cells_per_human = total_cells / M;
            int extra = total_cells % M;

            for (int i = 0; i < M; i++) {
                // Find my section boundaries
                // Recompute based on sorted assignment
                int my_start = human_wall_section[i];
                int rank_of_i = -1;
                // Determine how many cells this human is responsible for
                // We need to reconstruct which rank this human has
                std::vector<std::pair<int, int>> human_pos(M);
                for (int j = 0; j < M; j++) {
                    if (best_strip.edge < 2) human_pos[j] = {humans[j].c, j};
                    else human_pos[j] = {humans[j].r, j};
                }
                // Actually just compute section end from start
                int my_count = cells_per_human;
                // Check if this human gets an extra cell (first 'extra' humans sorted do)
                // Simpler: just find the next human's start to determine my end
                int my_end = total_cells; // default: goes to end
                for (int j = 0; j < M; j++) {
                    if (j == i) continue;
                    if (human_wall_section[j] > my_start && human_wall_section[j] < my_end) {
                        my_end = human_wall_section[j];
                    }
                }

                // Find nearest unbuilt wall cell in my section
                int best_idx = -1;
                int best_dist = INF;
                for (int w = my_start; w < my_end; w++) {
                    Point wc = wall_cells_to_build[w];
                    if (grid[wc.r][wc.c]) continue;
                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;
                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) { best_dist = dist; best_idx = w; }
                }

                // If my section is done, help with any remaining unbuilt cell
                if (best_idx == -1) {
                    for (int w = 0; w < total_cells; w++) {
                        Point wc = wall_cells_to_build[w];
                        if (grid[wc.r][wc.c]) continue;
                        bool claimed = false;
                        for (auto& wb : walls_being_built) {
                            if (wb == wc) { claimed = true; break; }
                        }
                        if (claimed) continue;
                        int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                        if (dist < best_dist) { best_dist = dist; best_idx = w; }
                    }
                }

                if (best_idx == -1) {
                    // All walls built - move to safe zone center
                    int tr = (best_strip.r_min + best_strip.r_max) / 2;
                    int tc = (best_strip.c_min + best_strip.c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        for (int r = best_strip.r_min; r <= best_strip.r_max; r++) {
                            for (int c = best_strip.c_min; c <= best_strip.c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_strip_target; }
                            }
                        }
                        found_strip_target:;
                    }
                    if (humans[i] != target) {
                        actions[i] = move_toward(humans[i], target);
                    }
                } else {
                    Point wall_target = wall_cells_to_build[best_idx];

                    // Find standing position: prefer safe side
                    Point stand_pos = {-1, -1};
                    int best_stand_dist = INF;
                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d];
                        int sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;
                        bool in_safe = is_safe_side_strip(sr, sc);
                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        int effective_dist = in_safe ? dist : dist + 50;
                        if (effective_dist < best_stand_dist) {
                            best_stand_dist = effective_dist;
                            stand_pos = {sr, sc};
                        }
                    }

                    if (stand_pos.r == -1) {
                        for (int d = 0; d < 4; d++) {
                            int sr = wall_target.r + DR[d];
                            int sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) { stand_pos = {sr, sc}; break; }
                        }
                    }

                    if (stand_pos.r == -1) {
                        actions[i] = '.';
                    } else if (humans[i] == stand_pos) {
                        if (can_build_wall(wall_target.r, wall_target.c)) {
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wall_target.r &&
                                    humans[i].c + DC[d] == wall_target.c) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back(wall_target);
                                    break;
                                }
                            }
                        } else {
                            // Pet blocking: try adjacent unbuilt wall cell
                            bool built_alt = false;
                            for (int w = 0; w < total_cells; w++) {
                                Point wc2 = wall_cells_to_build[w];
                                if (grid[wc2.r][wc2.c]) continue;
                                if (!can_build_wall(wc2.r, wc2.c)) continue;
                                bool adjacent = false;
                                int build_dir = -1;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        adjacent = true; build_dir = d; break;
                                    }
                                }
                                if (adjacent) {
                                    bool already_claimed = false;
                                    for (auto& wb : walls_being_built) {
                                        if (wb == wc2) { already_claimed = true; break; }
                                    }
                                    if (!already_claimed) {
                                        actions[i] = BUILD_CH[build_dir];
                                        walls_being_built.push_back(wc2);
                                        built_alt = true;
                                        break;
                                    }
                                }
                            }
                            if (!built_alt) actions[i] = '.';
                        }
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }
        } else {
            // Corner pair strategy (fallback from original)
            for (int i = 0; i < M; i++) {
                int my_plan = human_plan_assignment[i];
                auto& my_walls = plan_walls[my_plan];
                auto& plan = plans[my_plan];

                int best_idx = -1;
                int best_dist = INF;
                for (int w = 0; w < (int)my_walls.size(); w++) {
                    Point wc = my_walls[w];
                    if (grid[wc.r][wc.c]) continue;
                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;
                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) { best_dist = dist; best_idx = w; }
                }

                if (best_idx == -1) {
                    int tr = (plan.r_min + plan.r_max) / 2;
                    int tc = (plan.c_min + plan.c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        for (int r = plan.r_min; r <= plan.r_max; r++) {
                            for (int c = plan.c_min; c <= plan.c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_corner_target; }
                            }
                        }
                        found_corner_target:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    Point wall_target = my_walls[best_idx];
                    Point stand_pos = {-1, -1};
                    int best_stand_dist = INF;
                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d], sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;
                        bool in_safe = is_safe_side_corner(plan, sr, sc);
                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        int effective_dist = in_safe ? dist : dist + 100;
                        if (effective_dist < best_stand_dist) {
                            best_stand_dist = effective_dist;
                            stand_pos = {sr, sc};
                        }
                    }
                    if (stand_pos.r == -1) {
                        for (int d = 0; d < 4; d++) {
                            int sr = wall_target.r + DR[d], sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) { stand_pos = {sr, sc}; break; }
                        }
                    }
                    if (stand_pos.r == -1) {
                        actions[i] = '.';
                    } else if (humans[i] == stand_pos) {
                        if (can_build_wall(wall_target.r, wall_target.c)) {
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wall_target.r &&
                                    humans[i].c + DC[d] == wall_target.c) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back(wall_target);
                                    break;
                                }
                            }
                        } else {
                            bool built_alt = false;
                            for (int w2 = 0; w2 < (int)my_walls.size(); w2++) {
                                if (w2 == best_idx) continue;
                                Point wc2 = my_walls[w2];
                                if (grid[wc2.r][wc2.c]) continue;
                                if (!can_build_wall(wc2.r, wc2.c)) continue;
                                bool adjacent = false; int build_dir = -1;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        adjacent = true; build_dir = d; break;
                                    }
                                }
                                if (adjacent) {
                                    actions[i] = BUILD_CH[build_dir];
                                    walls_being_built.push_back(wc2);
                                    built_alt = true; break;
                                }
                            }
                            if (!built_alt) actions[i] = '.';
                        }
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
