        for (int i = 0; i < M; i++) {
            if (!is_safe_side_strip(humans[i].r, humans[i].c)) {
                all_on_safe_side = false;
                break;
            }
        }

        if (all_on_safe_side && !grid[gap_cell.r][gap_cell.c]) {
            // Seal the gap: find a human adjacent to gap cell
            for (int i = 0; i < M; i++) {
                for (int d = 0; d < 4; d++) {
                    if (humans[i].r + DR[d] == gap_cell.r &&
                        humans[i].c + DC[d] == gap_cell.c) {
                        if (can_build_wall(gap_cell.r, gap_cell.c)) {
                            actions[i] = BUILD_CH[d];
                            walls_being_built.push_back(gap_cell);
                        }
                        goto done_gap_seal;
                    }
                }
            }
            done_gap_seal:;
            // Others move to safe zone
            for (int i = 0; i < M; i++) {
                if (actions[i] != '.') continue;
                // Move toward gap cell to be adjacent for sealing
                Point adj_safe = {-1, -1};
                for (int d = 0; d < 4; d++) {
                    int sr = gap_cell.r + DR[d], sc = gap_cell.c + DC[d];
                    if (passable(sr, sc) && is_safe_side_strip(sr, sc)) {
                        adj_safe = {sr, sc}; break;
                    }
                }
                if (adj_safe.r != -1 && humans[i] != adj_safe) {
                    actions[i] = move_toward(humans[i], adj_safe);
                }
            }
        } else if (!all_on_safe_side) {
            // Move humans through the gap to safe side
            for (int i = 0; i < M; i++) {
                if (is_safe_side_strip(humans[i].r, humans[i].c)) continue;
                // Move toward gap cell then through it
                Point through_target = {-1, -1};
                for (int d = 0; d < 4; d++) {
                    int sr = gap_cell.r + DR[d], sc = gap_cell.c + DC[d];
                    if (passable(sr, sc) && is_safe_side_strip(sr, sc)) {
                        through_target = {sr, sc}; break;
                    }
                }
                if (through_target.r != -1) {
                    actions[i] = move_toward(humans[i], through_target);
                } else {
                    actions[i] = move_toward(humans[i], gap_cell);
                }
            }
        } else {
            // Gap already sealed, move to center
            for (int i = 0; i < M; i++) {
                int tr = (best_strip.r_min + best_strip.r_max) / 2;
                int tc = (best_strip.c_min + best_strip.c_max) / 2;
                Point target = {tr, tc};
                if (!passable(target.r, target.c)) {
                    for (int r = best_strip.r_min; r <= best_strip.r_max; r++)
                        for (int c = best_strip.c_min; c <= best_strip.c_max; c++)
                            if (passable(r, c)) { target = {r, c}; goto found_center; }
                    found_center:;
                }
                if (humans[i] != target) actions[i] = move_toward(humans[i], target);
