            int my_end = total_cells;
            for (int j = 0; j < M; j++) {
                if (j == i) continue;
                if (human_wall_section[j] > my_start && human_wall_section[j] < my_end)
                    my_end = human_wall_section[j];
            }

            // Find nearest unbuilt wall cell in my section (skip gap)
            int best_idx = -1;
            int best_dist = INF;
            for (int w = my_start; w < my_end; w++) {
                if (w == gap_cell_idx) continue;
                Point wc = wall_cells_to_build[w];
                if (grid[wc.r][wc.c]) continue;
                bool claimed = false;
                for (auto& wb : walls_being_built) {
                    if (wb == wc) { claimed = true; break; }
                }
                if (claimed) continue;
                int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                if (dist < best_dist) { best_dist = dist; best_idx = w; }
            }

            // Help with other sections if mine is done
            if (best_idx == -1) {
                for (int w = 0; w < total_cells; w++) {
                    if (w == gap_cell_idx) continue;
                    Point wc = wall_cells_to_build[w];
                    if (grid[wc.r][wc.c]) continue;
                    bool claimed = false;
                    for (auto& wb : walls_being_built) {
                        if (wb == wc) { claimed = true; break; }
                    }
                    if (claimed) continue;
                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) { best_dist = dist; best_idx = w; }
                }
            }

            if (best_idx == -1) {
                // My walls done, move toward gap to prepare for funnel
                Point adj_safe = {-1, -1};
                for (int d = 0; d < 4; d++) {
                    int sr = gap_cell.r + DR[d], sc = gap_cell.c + DC[d];
                    if (passable(sr, sc) && is_safe_side_strip(sr, sc)) {
                        adj_safe = {sr, sc}; break;
                    }
                }
                if (adj_safe.r != -1 && humans[i] != adj_safe) {
                    actions[i] = move_toward(humans[i], adj_safe);
                }
            } else {
                Point wall_target = wall_cells_to_build[best_idx];

                // Find closest standing position (any side, not just safe)
                Point stand_pos = {-1, -1};
                int best_stand_dist = INF;
                for (int d = 0; d < 4; d++) {
                    int sr = wall_target.r + DR[d], sc = wall_target.c + DC[d];
                    if (!passable(sr, sc)) continue;
                    int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                    if (dist < best_stand_dist) {
                        best_stand_dist = dist;
                        stand_pos = {sr, sc};
