    best.score = -1;
    // Find the best strip on the opposite edge
    int opp_edge = -1;
    if (first.edge == 0) opp_edge = 1;
    else if (first.edge == 1) opp_edge = 0;
    else if (first.edge == 2) opp_edge = 3;
    else opp_edge = 2;

    for (int depth = 3; depth <= 14; depth++) {
        StripPlan sp;
        sp.edge = opp_edge;
        sp.depth = depth;

        if (opp_edge == 0) {
            sp.wall_pos = depth + 1;
            sp.r_min = 1; sp.r_max = depth;
            sp.c_min = 1; sp.c_max = GRID_SIZE;
        } else if (opp_edge == 1) {
            sp.wall_pos = GRID_SIZE - depth;
            sp.r_min = GRID_SIZE - depth + 1; sp.r_max = GRID_SIZE;
            sp.c_min = 1; sp.c_max = GRID_SIZE;
        } else if (opp_edge == 2) {
            sp.wall_pos = depth + 1;
            sp.r_min = 1; sp.r_max = GRID_SIZE;
            sp.c_min = 1; sp.c_max = depth;
        } else {
            sp.wall_pos = GRID_SIZE - depth;
            sp.r_min = 1; sp.r_max = GRID_SIZE;
            sp.c_min = GRID_SIZE - depth + 1; sp.c_max = GRID_SIZE;
        }

        sp.area = (sp.r_max - sp.r_min + 1) * (sp.c_max - sp.c_min + 1);
        sp.pets_inside = 0;

        for (auto& p : pets) {
            if (p.r >= sp.r_min && p.r <= sp.r_max && p.c >= sp.c_min && p.c <= sp.c_max)
                sp.pets_inside++;
        }

        double base_score = (double)sp.area / 900.0 * std::pow(2.0, -(double)sp.pets_inside);
        double pet_bonus = (sp.pets_inside == 0) ? 2.5 : (sp.pets_inside == 1) ? 1.0 : 0.3;
        double area_bonus = std::sqrt((double)sp.area / 150.0);
        sp.score = base_score * pet_bonus * area_bonus;

        if (sp.score > best.score) best = sp;
    }
}

